//-------------------------------------------------------------------------
// Constructor
//-------------------------------------------------------------------------
MRFExportExcelCmd::MRFExportExcelCmd() :
CATStateCommand ("MRFExportExcelCmd", CATDlgEngOneShot, CATCommandModeShared)
//  Valid states are CATDlgEngOneShot and CATDlgEngRepeat
, _pExportUDFParamDlg(NULL)
, _pApplicationFrame(NULL)
, _pEditor(NULL)
, _pHSO(NULL)
, _pUDFInstDialogAgent(NULL)
, _pUDFInstPathElementAgent(NULL)
, _pUDFInstPathElement(NULL)
, _spMechanicalPart(NULL_var)
, _spCkeRelFact(NULL_var)
, _spCkeSheetExcel(NULL_var)
, _pExcelFileDialog(NULL)
{
	_pApplicationFrame = CATApplicationFrame::GetFrame();
	_pEditor = CATFrmEditor::GetCurrentEditor();
	if (NULL != _pEditor)
	{
		_pHSO = _pEditor->GetHSO();

		CATPathElement  oActivePath = _pEditor->GetUIActiveObject();
		oActivePath.InitToLeafElement();
		CATBaseUnknown_var spCBUOnCurrObject = oActivePath.NextFatherElement();

		if (NULL_var != spCBUOnCurrObject)
		{
			CATIMmiUsePrtPart * piPrtPart = NULL;
			spCBUOnCurrObject->QueryInterface(IID_CATIMmiUsePrtPart, (void**)&piPrtPart);
			if (NULL != piPrtPart)
			{
				_spMechanicalPart = piPrtPart;
				if (NULL_var != _spMechanicalPart)
				{
					CATIMmiPrtContainer_var spPrtCont;
					_spMechanicalPart->GetPrtContainer(spPrtCont);
					if (NULL_var != spPrtCont)
					{
						_spCkeRelFact = spPrtCont;
					}
				}
				piPrtPart->Release();  piPrtPart = NULL;
			}
		}
	}

	CATUnicodeString strCmdName = CATMsgCatalog::BuildMessage("MRFGenericProcessToolsCmdHeader", "MRFGenericProcessToolsCmdHeader.MRFExportExcelHdr.Title");
	const CATString sCmdName(strCmdName);

	_pExportUDFParamDlg = new CATDlgDialog((CATApplicationFrame::GetFrame())->GetMainWindow(), sCmdName, CATDlgGridLayout | CATDlgWndOK | CATDlgWndCANCEL | CATDlgWndNoResize);
	BuildDialog();
}

//-------------------------------------------------------------------------
// Destructor
//-------------------------------------------------------------------------
MRFExportExcelCmd::~MRFExportExcelCmd()
{

	if (NULL != _pExportUDFParamDlg)
		_pExportUDFParamDlg->RequestDelayedDestruction(); _pExportUDFParamDlg = NULL;

	if (NULL != _pApplicationFrame)
		_pApplicationFrame = NULL;

	if (NULL != _pEditor)
		_pEditor = NULL;

	if (NULL != _pHSO)
		_pHSO = NULL;

	if (NULL != _pUDFInstLabel)
		_pUDFInstLabel = NULL;

	if (NULL != _pUDFInstSelector)
		_pUDFInstSelector = NULL;

	if (NULL != _pMainFrame)
		_pMainFrame = NULL;

	if (NULL != _pExcelFileDialog)
		_pExcelFileDialog = NULL;

	if (NULL_var != _spCkeRelFact)
		_spCkeRelFact = NULL_var;

	if (_pUDFInstDialogAgent)
		_pUDFInstDialogAgent->RequestDelayedDestruction(); _pUDFInstDialogAgent = NULL;

	if (_pUDFInstPathElementAgent)
		_pUDFInstPathElementAgent->RequestDelayedDestruction(); _pUDFInstPathElementAgent = NULL;

	if (_pUDFInstPathElement)
		_pUDFInstPathElement = NULL;

}


//-------------------------------------------------------------------------
// BuildGraph()
//-------------------------------------------------------------------------
void MRFExportExcelCmd::BuildGraph()
{
	if (!!_pExportUDFParamDlg)
	{
		AddAnalyseNotificationCB(_pExportUDFParamDlg, _pExportUDFParamDlg->GetDiaOKNotification(), (CATCommandMethod)& MRFExportExcelCmd::ActionOne, NULL);
		AddAnalyseNotificationCB(_pExportUDFParamDlg, _pExportUDFParamDlg->GetDiaCANCELNotification(), (CATCommandMethod)& MRFExportExcelCmd::ActionClose, NULL);
		AddAnalyseNotificationCB(_pExportUDFParamDlg, _pExportUDFParamDlg->GetWindCloseNotification(), (CATCommandMethod)& MRFExportExcelCmd::ActionClose, NULL);

		CATListOfCATString List3DElements;
		List3DElements.Append("CATIUdfFeatureInstance");

		_pUDFInstPathElementAgent = new CATPathElementAgent("RefElementPathElementAgent");
		if (_pUDFInstPathElementAgent)
		{
			_pUDFInstPathElementAgent->SetOrderedTypeList(List3DElements);
			_pUDFInstPathElementAgent->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);

		}
		_pUDFInstDialogAgent = new CATDialogAgent("UDFInstDialogAgent");
		if (!!_pUDFInstDialogAgent && !!_pUDFInstSelector)
		{
			_pUDFInstDialogAgent->AcceptOnNotify(_pUDFInstSelector, _pUDFInstSelector->GetListSelectNotification());
		}
		CATDialogState * pInitialState = GetInitialState("InitialState");
		pInitialState->AddDialogAgent(_pUDFInstDialogAgent);
		pInitialState->AddDialogAgent(_pUDFInstPathElementAgent);

		AddTransition(pInitialState, pInitialState, IsOutputSetCondition(_pUDFInstDialogAgent), Action((ActionMethod)&MRFExportExcelCmd::OnSelectorListSelected));
		AddTransition(pInitialState, pInitialState, IsOutputSetCondition(_pUDFInstPathElementAgent), Action((ActionMethod)&MRFExportExcelCmd::OnObjectSelection));
	}

}


//-------------------------------------------------------------------------
// ActionOne ()
//-------------------------------------------------------------------------
void MRFExportExcelCmd::ActionOne(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	ExportParamters();		
	return;
}

void MRFExportExcelCmd::ActionClose(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	this->ExecuteUndoAtEnd();
	RequestDelayedDestruction();

	return;
}

void MRFExportExcelCmd::BuildDialog()
{
	if (!!_pExportUDFParamDlg)
	{
		_pMainFrame = new CATDlgFrame(_pExportUDFParamDlg, (const char*)"MainFrame", 0 | CATDlgFraNoTitle | CATDlgFraNoFrame | CATDlgGridLayout);
		if (NULL != _pMainFrame)
		{
			_pMainFrame->SetGridConstraints(0, 0, 2, 2, CATGRID_4SIDES);

			CATUnicodeString strLblName = CATMsgCatalog::BuildMessage("MRFGenericProcessToolsCmdHeader", "MRFExportExcelHdr.ExportSpecCmd.Label");

			_pUDFInstLabel = new CATDlgLabel(_pMainFrame, (const char*)strLblName, 0 | CATDlgLabLeft);
			_pUDFInstSelector = new CATDlgSelectorList(_pMainFrame, (const char*)"ElementSelector", 0);
			if (NULL != _pUDFInstLabel && NULL != _pUDFInstSelector)
			{
				_pUDFInstLabel->SetGridConstraints(0, 0, 2, 1, CATGRID_4SIDES);
				_pUDFInstSelector->SetGridConstraints(0, 2, 4, 1, CATGRID_4SIDES);
				_pUDFInstSelector->SetVisibleTextHeight(1);
				_pUDFInstSelector->SetVisibleTextWidth(20);
				_pUDFInstSelector->SetLine("No Selection");
			}
		}
		_pExportUDFParamDlg->SetVisibility(CATDlgShow);
	}
}

CATBoolean MRFExportExcelCmd::OnSelectorListSelected(void * iUsefulData)
{
	if (!!_pExportUDFParamDlg)
	{
		if (!!_pUDFInstSelector)
		{
			static int arrRow[1] = { 0 };
			_pUDFInstSelector->SetSelect(arrRow, 1, 0);
		}

		if (NULL != _pHSO)
		{
			_pHSO->Empty();
			if (NULL != _pUDFInstPathElement && 0 == _pHSO->IsMember(_pUDFInstPathElement))
				_pHSO->AddElement(_pUDFInstPathElement);
		}
	}
	if (!!_pUDFInstDialogAgent)
		_pUDFInstDialogAgent->InitializeAcquisition();
	return CATTrue;
}


CATBoolean MRFExportExcelCmd::OnObjectSelection(void * iUsefulData)
{
	if (!!_pUDFInstPathElementAgent && !!_pExportUDFParamDlg && NULL != _pHSO)
	{
		_pUDFInstPathElement = _pUDFInstPathElementAgent->GetValue();
		if (NULL != _pUDFInstPathElement)
		{
			_spUDFInst = NULL_var;
			_spUDFInst = _pUDFInstPathElement->CurrentElement();
			if (NULL_var != _spUDFInst)
			{
				CATIAlias_var spAlias = _spUDFInst;
				if (NULL_var != spAlias)
				{
					_strUDFInstName = spAlias->GetAlias();
				}
				if (!!_pUDFInstSelector)
				{
					_pUDFInstSelector->ClearLine();
					_pUDFInstSelector->SetLine(_strUDFInstName);
					static int arrRow[1] = { 0 };
					_pUDFInstSelector->SetSelect(arrRow, 1, 0);
				}
				_pHSO->Empty();
				_pHSO->AddElement(_pUDFInstPathElement);

			}
		

			if (NULL_var == _spUDFInst)
			{
				_pHSO->Empty();
				CATUnicodeString strErrorMsg = "Selected element is not a UDF instance.\nPlease select an UDF instance.";
				MRFGenericUtils::ShowErrorMessage(strErrorMsg);
				if (!!_pUDFInstSelector)
				{
					_pUDFInstSelector->ClearLine();
					_pUDFInstSelector->SetLine("No Selection");
				}
			}
		}
		_pUDFInstPathElementAgent->InitializeAcquisition();
	}
	return CATTrue;
}

void MRFExportExcelCmd::ExportParamters()
{
	_strListParamNames.RemoveAll();
	_strListParamValues.RemoveAll();

	if (NULL_var != _spUDFInst)
	{
		CATIKweModelServices_var spKweModelServices = CATCkeGlobalFunctions::GetModelServices();
		if (NULL_var != spKweModelServices)
		{
			CATListValCATBaseUnknown_var spListOfParm;
			spKweModelServices->VisibleParms(_spUDFInst, spListOfParm);

			if (spListOfParm.Size() > 0)

		/*CATListValCATBaseUnknown_var * spParametersList = NULL;
		HRESULT rc = _spUDFInst->GetParameters(spParametersList);*

		if (NULL != spParametersList)
		{*/
			for (int i = 1; i <= spListOfParm.Size(); i++)
			{
				CATICkeParm_var spParm = (spListOfParm)[i];
				if (!spParm)
					continue;
				CATUnicodeString ParameterName = MRFGenericUtils::GetParmNameSplittedFromCATICkeParm(spParm);
				CATUnicodeString strType = spParm->Type()->Name();
				CATBoolean bProceed = CATTrue;
				CATUnicodeString ParameterValue = MRFGenericUtils::GetParamValue(spParm);
				
				if (strType.Compare("Boolean") > 0 && 2 == ParameterName.Compare("Activity"))
				{
					bProceed = CATFalse;
				}

				if (bProceed)
				{
					_strListParamNames.Append(ParameterName);
					_strListParamValues.Append(ParameterValue);
				}
			}
		}

	}
	if (_strListParamValues.Size() > 0 && _strListParamValues.Size() == _strListParamNames.Size())
		LaunchSaveWindow();
	else
	{
		CATUnicodeString strErrorMsg = "Selected element is not a UDF instance or No paramters found in UDF instance to export.";
		MRFGenericUtils::ShowErrorMessage(strErrorMsg);
	}
}

void MRFExportExcelCmd::LaunchSaveWindow()
{
	if (_pExcelFileDialog == NULL)
		_pExcelFileDialog = new CATDlgFile(_pExportUDFParamDlg, "Save File", CATDlgWndModal | CATDlgFileSave);

#ifdef _WINDOWS_SOURCE

	CATUnicodeString nameExtension[3];
	nameExtension[0] = CATUnicodeString("Excel File (*.xlsx)");
	nameExtension[1] = CATUnicodeString("Excel File (*.xls)");
	nameExtension[2] = CATUnicodeString("Excel File (*All files)");
	CATString        filterExtension[3];
	filterExtension[0] = CATString("*.xlsx");
	filterExtension[1] = CATString("*.xls");
	filterExtension[2] = CATString("*.xlsx;*.xls");


	_pExcelFileDialog->SetFilterStrings(nameExtension, filterExtension, 3); // Sets the search filter. Only Excel files are allowed.

#else

	_pExcelFileDialog->SetFilterPattern("*.xlsx");

#endif

	// Subscribes to the event sent when the user selects the Ok button or
	// double-clicks a file
	AddAnalyseNotificationCB(_pExcelFileDialog,
		_pExcelFileDialog->GetDiaOKNotification(),
		(CATCommandMethod)&MRFExportExcelCmd::OnOKExcelFile,
		NULL);

	// Subscribes to the event sent when the user selects the Cancel button or
	// closes the dialog
	AddAnalyseNotificationCB(_pExcelFileDialog,
		_pExcelFileDialog->GetDiaCANCELNotification(),
		(CATCommandMethod)&MRFExportExcelCmd::OnCANCELExcelFile,
		NULL);

	_pExportUDFParamDlg->SetVisibility(CATDlgHide);
	_pExcelFileDialog->SetVisibility(CATDlgShow);


}

//========================OnOKExcelFile============================================//
// This function is invoked when OK button is clicked in the Excel SAVE selection window
void MRFExportExcelCmd::OnOKExcelFile(CATCommand* ipControl, CATNotification* ipNotification, CATCommandClientData iUsefulData)
{
	CATUnicodeString isfilePathName, isPathName, isfileName;
	_pExcelFileDialog->GetSelection(isfilePathName);
	int size = _strListParamNames.Size();
	string strFileXL = isfilePathName;
	_spCkeSheetExcel = _spCkeRelFact->CreateSheet(isfilePathName, 1);
	if (NULL_var != _spCkeSheetExcel)
	{
		int row = 1;
		int col = 1;
		for (int i = 1; i <= size; i++)
		{
			row = i;
			CATUnicodeString columnOne = _strListParamNames[i], columnTwo = _strListParamValues[i];

			if (i == 1)
				_spCkeSheetExcel->SetCell(row, col, columnOne, 1, 0);
			else
				_spCkeSheetExcel->SetCell(row, col, columnOne, 0, 0);

			if (i != size)
				_spCkeSheetExcel->SetCell(row, col + 1, columnTwo, 0, 0);
			else
				_spCkeSheetExcel->SetCell(row, col + 1, columnTwo, 0, 1);
		}
		_spCkeSheetExcel->UpdateLocalCopy();
	}
	if (_pExcelFileDialog)
	{
		_pExcelFileDialog->RequestDelayedDestruction();
		_pExcelFileDialog = NULL;
		if (CATDlgHide == _pExportUDFParamDlg->GetVisibility())
		{
			_pExportUDFParamDlg->SetVisibility(CATDlgShow);
			RequestDelayedDestruction();
		}

	}


	return;
}

//========================OnCANCELExcelFile============================================//
// This function is invoked when Cancel button is clicked in the Excel import selection window
void MRFExportExcelCmd::OnCANCELExcelFile(CATCommand* iPublishingCommand, CATNotification* ipNotification, CATCommandClientData iUsefulData)
{
	if (_pExcelFileDialog)
	{
		_pExcelFileDialog->RequestDelayedDestruction();
		_pExcelFileDialog = NULL;
	}

	if (CATDlgHide == _pExportUDFParamDlg->GetVisibility())
		_pExportUDFParamDlg->SetVisibility(CATDlgShow);

	return;
}